effects.wgsl:
const Du = 1.0;      // substrate diffusion
const Dv = 0.5;      // activator diffusion (slower → patterns, not a smear)
const F  = 0.0367;   // feed  — replenish U
const K  = 0.0649;   // kill  — remove V   (F,K in the "mitosis" pocket)
const DT = 1.0;

fn rd_at(c: vec2f) -> vec4f { return textureSampleLevel(feedbackTex, texSampler, feedbackUV(c), 0.0); }
fn rd_U(c: vec2f) -> f32 { return 1.0 - rd_at(c).r; }
fn rd_V(c: vec2f) -> f32 { return rd_at(c).g; }

// per-block hash → sparse seed scatter
fn rd_hash(p: vec2f) -> f32 { return fract(sin(dot(floor(p), vec2f(127.1, 311.7))) * 43758.5453); }

fn fieldEffect(coord: vec2f, regionMin: vec2f, regionMax: vec2f, time: f32, params: vec4f) -> vec4f {
  let U = rd_U(coord);
  let V = rd_V(coord);

  // 9-point Laplacian (weights sum to zero): edges 0.2, corners 0.05, centre -1
  let uE = rd_U(coord+vec2f(1.,0.)) + rd_U(coord+vec2f(-1.,0.)) + rd_U(coord+vec2f(0.,1.)) + rd_U(coord+vec2f(0.,-1.));
  let uC = rd_U(coord+vec2f(1.,1.)) + rd_U(coord+vec2f(-1.,1.)) + rd_U(coord+vec2f(1.,-1.)) + rd_U(coord+vec2f(-1.,-1.));
  let vE = rd_V(coord+vec2f(1.,0.)) + rd_V(coord+vec2f(-1.,0.)) + rd_V(coord+vec2f(0.,1.)) + rd_V(coord+vec2f(0.,-1.));
  let vC = rd_V(coord+vec2f(1.,1.)) + rd_V(coord+vec2f(-1.,1.)) + rd_V(coord+vec2f(1.,-1.)) + rd_V(coord+vec2f(-1.,-1.));
  let lapU = uE * 0.2 + uC * 0.05 - U;
  let lapV = vE * 0.2 + vC * 0.05 - V;

  let reaction = U * V * V;
  var nU = U + (Du * lapU - reaction + F * (1.0 - U)) * DT;
  var nV = V + (Dv * lapV + reaction - (F + K) * V) * DT;

  // init: for the first breath, force a clean field (U=1) with scattered V seeds,
  // regardless of whatever the feedback texture held before boot
  if (time < 0.6) {
    nU = 1.0;
    nV = step(0.90, rd_hash(coord / 5.0));
  }

  // your cursor seeds life — drag to grow new coral (a hook writes cell in params.xy)
  let cur = params.xy;
  if (cur.x > 0.5) {
    let dc = length(coord - cur);
    nV += smoothstep(9.0, 0.0, dc) * 0.6;
  }

  // NaN guard (a single poisoned cell would spread through diffusion)
  if (!(nU == nU) || !(nV == nV)) { nU = 1.0; nV = 0.0; }
  nU = clamp(nU, 0.0, 1.0);
  nV = clamp(nV, 0.0, 1.0);

  // encode state + paint. R=1-U (red structure), G=V (green front), B=glow.
  let structure = clamp(1.0 - nU, 0.0, 1.0);
  let front = clamp(nV, 0.0, 1.0);
  let b = clamp(front * 5.0, 0.0, 1.0) * 0.9 + structure * structure * 0.18;
  return vec4f(structure, front, b, 1.0);
}

stepHooks.code:
try {
      const wd = sim.worldData
      const f = sim.fields.get('reef_f')
      const mx = wd.mouse_x, my = wd.mouse_y
      const p = (typeof mx === 'number') ? [mx, my, 0, 0] : [-1, -1, 0, 0]
      if (f && f.effects) { for (const e of f.effects) e.params = p }
    } catch (e) {}

visualTypes.wgsl:
fn visual_reef_base(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let d = length(uv);
  return vec4f(vec3f(0.01, 0.015, 0.03) * (1.0 - d * 0.6), 1.0);
}
